SELECT t.id, t.title, t.description, t.created_by, t.created_at, COALESCE(NULLIF(u.display_name, ''), u.username) AS created_by_name FROM topic t LEFT JOIN users u ON t.created_by = u.id
(t.title LIKE CONCAT('%', #{keyword}, '%') OR t.description LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY t.id DESC LIMIT #{pageSize} OFFSET #{offset}
